const items = $input.all().map(i => i.json);
const users = items.length === 1 && Array.isArray(items[0]) ? items[0] : items;
const userMap = {};
for (const u of users) {
  if (u && u.close_user_id) userMap[u.close_user_id] = u.id;
}
return [{ json: { userMap } }];

const triggerData = $('Start').first().json;
const since = triggerData.since || new Date().toISOString();
const until = triggerData.until || new Date().toISOString();
const currentDate = since.split('T')[0];
const endDate = until.split('T')[0];
return [{ json: { cursor: '', totalSynced: 0, currentDate, endDate, pageCount: 0 } }];

const data = $input.first().json;
const queries = [
  { type: 'object_type', object_type: 'opportunity' },
  {
    type: 'field_condition',
    field: { type: 'regular_field', object_type: 'opportunity', field_name: 'date_updated' },
    condition: {
      type: 'moment_range',
      on_or_after: { type: 'fixed_local_date', value: data.currentDate, which: 'start' },
      before: { type: 'fixed_local_date', value: data.currentDate, which: 'end' }
    }
  }
];

const body = {
  query: { type: 'and', queries },
  sort: [{ direction: 'asc', field: { object_type: 'opportunity', type: 'regular_field', field_name: 'date_updated' } }],
  _fields: { opportunity: ['id', 'lead_id', 'user_id', 'created_by', 'status_display_name', 'status_label', 'pipeline_name', 'pipeline_id', 'value', 'value_period', 'value_formatted', 'value_currency', 'confidence', 'loss_reason', 'expected_close_date', 'date_won', 'date_lost', 'date_created', 'date_updated', 'contact_id', 'contact_name', 'note', 'custom'] },
  _limit: 200
};
if (data.cursor) body.cursor = data.cursor;
return [{ json: { requestBody: JSON.stringify(body) } }];

const response = $input.first().json;
const opportunities = response.data || [];
const userMap = $('Build User Map').first().json.userMap;

if (opportunities.length === 0) {
  return [{ json: { _empty: true } }];
}

const stdFields = new Set(['id','lead_id','user_id','created_by','status_display_name','status_label','pipeline_name','pipeline_id','value','value_period','value_formatted','value_currency','confidence','loss_reason','expected_close_date','date_won','date_lost','date_created','date_updated','organization_id','_type','lead_name','user_name','created_by_name','contact_id','contact_name','status_id','status_type','annualized_value','annualized_expected_value','note','integration_links','__object_type']);

return opportunities.map(opp => {
  const val = opp.value != null ? opp.value / 100 : null;
  let monthlyVal = null;
  if (val != null) {
    if (opp.value_period === 'monthly') monthlyVal = val;
    else if (opp.value_period === 'annual') monthlyVal = Math.round(val / 12 * 100) / 100;
  }

  const cf = {};
  for (const [k, v] of Object.entries(opp)) {
    if (!stdFields.has(k)) cf[k] = v;
  }

  return {
    json: {
      close_opportunity_id: opp.id,
      close_lead_id: opp.lead_id || null,
      user_id: userMap[opp.user_id] || null,
      setter_id: userMap[opp.created_by] || null,
      status: opp.status_display_name || opp.status_label || null,
      product: opp.pipeline_name || null,
      value: val,
      setup_fee: null,
      monthly_value: monthlyVal,
      contract_duration: null,
      confidence: opp.confidence != null ? opp.confidence : null,
      lost_reason: opp.loss_reason || null,
      forecast_close_date: opp.expected_close_date || null,
      closed_at: opp.date_won || opp.date_lost || null,
      close_created_at: opp.date_created || null,
      custom_fields: Object.keys(cf).length > 0 ? cf : null,
      synced_at: new Date().toISOString()
    }
  };
});

const allOpps = $input.all().map(i => i.json).filter(i => !i._empty);
const nullUserIds = allOpps.filter(r => r.user_id === null).length;
return [{ json: { batch: allOpps, count: allOpps.length, nullUserIds } }];

const response = $('Search Close Opportunities').first().json;
const items = response.data || [];
const cursor = response.cursor || null;

const prev = $('Check More Pages').isExecuted
  ? $('Check More Pages').first().json
  : $('Init Pagination').first().json;

const batchCount = $('Aggregate Batch').first().json.count;
const cursorValid = cursor !== null && cursor !== undefined && cursor !== '';

if (cursorValid && items.length > 0) {
  return [{ json: {
    currentDate: prev.currentDate,
    endDate: prev.endDate,
    cursor: cursor,
    totalSynced: prev.totalSynced + batchCount,
    pageCount: (prev.pageCount || 0) + 1,
    hasMore: true
  } }];
}

const next = new Date(prev.currentDate + 'T00:00:00Z');
next.setUTCDate(next.getUTCDate() + 1);
const nextDate = next.toISOString().split('T')[0];
const hasMore = nextDate <= prev.endDate;

return [{ json: {
  currentDate: nextDate,
  endDate: prev.endDate,
  cursor: '',
  totalSynced: prev.totalSynced + batchCount,
  pageCount: 0,
  hasMore
} }];

const check = $('Check More Pages').last().json;
const totalSynced = check.totalSynced;
const syncRunId = $('Sync Start').first().json.id;
const nullUsers = check.totalNullUserIds || 0;
let warning = '';
if (nullUsers > 0) {
  warning = 'FK Warning: ' + nullUsers + '/' + totalSynced + ' null user_ids';
}
return [{ json: { count: totalSynced, syncRunId, warning } }];
